import { makeId } from './id'
import type { Entry } from '../types'

const SAMPLE_ENTRY_DATA: Array<{ name: string; image: string }> = [
  { name: "Flavio", image: "data:image/png;base64," },
  { name: "Jannik", image: "data:image/png;base64," },
  { name: "Jasmine", image: "data:image/png;base64," },
  { name: "Lorenzo", image: "data:image/png;base64," },
  { name: "Matteo", image: "data:image/png;base64," },
]

export function createSampleEntries(): Entry[] {
  return SAMPLE_ENTRY_DATA.map(({ name, image }) => ({ id: makeId(), name, image }))
}
